const ANTHROPIC_API_KEY = 'REPLACE_WITH_ANTHROPIC_KEY';
const item = $input.first().json;

const systemPrompt = 'You are a professional news editor for Cameroon Concord, an independent digital media platform covering Cameroon and Central Africa. Write in the style of Reuters Africa — factual, concise, and impartial. Output must always be in English. Do not use sensationalist language. Do not use tribal, ethnic, or regional framing. Do not editorialize. Focus on verified facts and credible context.';

const rawBody = (item.raw_body || '').substring(0, 2000);
const userPrompt = `You are given a raw news item from a Cameroon news source. Evaluate and produce social media copy.\n\nRAW TITLE: ${item.raw_title}\nRAW BODY: ${rawBody}\nSOURCE: ${item.source_name}\nLANGUAGE: ${item.language}\n\nIf publishable, respond ONLY with valid JSON:\n{\n  "headline": "Clean news headline max 80 chars",\n  "facebook_post": "150-250 word Reuters-style post ending with hook question, no hashtags in body",\n  "twitter_post": "Max 240 chars punchy and factual, no hashtags in body",\n  "hashtags_facebook": ["tag1","tag2","tag3","tag4","tag5"],\n  "hashtags_twitter": ["tag1","tag2","tag3"],\n  "category": "politics|economy|security|society|sports|culture|environment",\n  "image_search_query": "4-6 word stock photo query",\n  "publish": true,\n  "reject_reason": null\n}\n\nIf rejecting:\n{\n  "publish": false,\n  "reject_reason": "Brief reason why rejected"\n}`;

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 1000,
  system: systemPrompt,
  messages: [{ role: 'user', content: userPrompt }]
});

return [{
  json: {
    api_key: ANTHROPIC_API_KEY,
    request_body: requestBody,
    ingested_id: item.id,
    raw_image_url: item.raw_image_url,
    source_url: item.source_url,
    source_name: item.source_name,
    raw_title: item.raw_title
  }
}];

const claudeResponse = $input.first().json;
const promptData = $('Build Claude Prompt').all()[$itemIndex].json;

const content = claudeResponse.content && claudeResponse.content[0]
  ? claudeResponse.content[0].text
  : '';

let parsed;
try {
  const match = content.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON found in Claude response');
  parsed = JSON.parse(match[0]);
} catch (e) {
  parsed = { publish: false, reject_reason: 'Parse error: ' + e.message };
}

return [{
  json: {
    ...parsed,
    ingested_id: promptData.ingested_id,
    raw_image_url: promptData.raw_image_url,
    source_url: promptData.source_url,
    source_name: promptData.source_name
  }
}];

const FB_PAGE_ID = 'REPLACE_WITH_FB_PAGE_ID';
const FB_PAGE_TOKEN = 'REPLACE_WITH_FB_PAGE_TOKEN';
const REPLACE_WITH_TWITTER_BEARER = 'REPLACE_WITH_TWITTER_BEARER';
const REPLACE_WITH_TWITTER_API_KEY = 'REPLACE_WITH_TWITTER_API_KEY';
const REPLACE_WITH_TWITTER_API_SECRET = 'REPLACE_WITH_TWITTER_API_SECRET';
const REPLACE_WITH_TWITTER_ACCESS_TOKEN = 'REPLACE_WITH_TWITTER_ACCESS_TOKEN';
const REPLACE_WITH_TWITTER_ACCESS_SECRET = 'REPLACE_WITH_TWITTER_ACCESS_SECRET';

const item = $input.first().json;

const fbHashtags = (item.hashtags_facebook || []).map(h => '#' + h.replace(/^#/, '')).join(' ');
const fbCaption = item.facebook_post + '\n\n' + fbHashtags;

const twHashtags = (item.hashtags_twitter || []).map(h => '#' + h.replace(/^#/, '')).join(' ');
const twitterPost = (item.twitter_post + ' ' + twHashtags).substring(0, 280);

const hasImage = !!item.raw_image_url && !item.raw_image_url.startsWith('tg_file:');

let fbEndpoint, fbBodyObj;
if (hasImage) {
  fbEndpoint = `https://graph.facebook.com/v19.0/${FB_PAGE_ID}/photos`;
  fbBodyObj = { caption: fbCaption, url: item.raw_image_url, access_token: FB_PAGE_TOKEN };
} else {
  fbEndpoint = `https://graph.facebook.com/v19.0/${FB_PAGE_ID}/feed`;
  fbBodyObj = { message: fbCaption, access_token: FB_PAGE_TOKEN };
}

return [{
  json: {
    fb_endpoint: fbEndpoint,
    fb_body_str: JSON.stringify(fbBodyObj),
    pass_through: {
      ingested_id: item.ingested_id,
      category: item.category,
      source_url: item.source_url,
      headline: item.headline,
      image_url: hasImage ? item.raw_image_url : null,
      facebook_post: fbCaption,
      twitter_post: twitterPost
    }
  }
}];

const response = $input.first().json;
const passThrough = $('Build Facebook Payload').all()[$itemIndex].json.pass_through;

if (response.error) {
  return [{
    json: {
      fb_success: false,
      error_message: response.error.message || JSON.stringify(response.error),
      pass_through: passThrough
    }
  }];
}

const fbPostId = response.post_id || response.id || null;

return [{
  json: {
    fb_success: true,
    fb_post_id: fbPostId,
    pass_through: passThrough
  }
}];

const item = $input.first().json;
const passThrough = item.pass_through;

return [{
  json: {
    twitter_text: passThrough.twitter_post,
    pass_through: passThrough,
    fb_post_id: item.fb_post_id
  }
}];

const twitterResult = $input.first().json;
const tweetPayload = $('Build Twitter Payload').all()[$itemIndex].json;
const pt = tweetPayload.pass_through;

const twitterPostId = twitterResult.data
  ? twitterResult.data.id
  : (twitterResult.id || null);

return [{
  json: {
    ingested_id: pt.ingested_id,
    category: pt.category,
    source_url: pt.source_url,
    fb_post_id: tweetPayload.fb_post_id,
    fb_caption: pt.facebook_post,
    twitter_post_id: twitterPostId,
    twitter_caption: pt.twitter_post,
    image_url: pt.image_url
  }
}];

const results = $('Prepare Results').all()[$itemIndex].json;

return [
  {
    json: {
      ingested_id: results.ingested_id,
      platform: 'facebook',
      caption: results.fb_caption,
      image_url: results.image_url,
      image_source: results.image_url ? 'source' : null,
      image_moderation_status: 'approved',
      status: 'published',
      platform_post_id: results.fb_post_id,
      error_message: null
    }
  },
  {
    json: {
      ingested_id: results.ingested_id,
      platform: 'twitter',
      caption: results.twitter_caption,
      image_url: null,
      image_source: null,
      image_moderation_status: 'approved',
      status: results.twitter_post_id ? 'published' : 'failed',
      platform_post_id: results.twitter_post_id,
      error_message: results.twitter_post_id ? null : 'Twitter post failed'
    }
  }
];

const d = $input.first().json;
return [{
  json: {
    message: 'Content publishing run complete',
    published_pairs: Math.floor(d.published_count / 2),
    timestamp: new Date().toISOString()
  }
}];
